fn nesting_depth(n: i64) -> i64 = {
    if n < 0 { -1 }
    else {
        let mut depth = 0;
        let mut val = n;
        while val >= 10 {
            val = val / 10;
            depth = depth + 1
        };
        depth
    }
};

